// C9 Mitigation: tenant_id NIEMALS aus dem Payload lesen.
// Die Rufnummer (did_number) ist der autoritative Tenant-Lookup-Schlüssel.
// Lookup: SELECT tenant_id FROM tenant_did_numbers WHERE did_number = $1 LIMIT 1
const payload = $input.first().json.body;
const didNumber = payload?.did_number;
if (!didNumber) {
  throw new Error('did_number fehlt im Ereignis-Payload');
}
// did_number wird an den nächsten Knoten weitergegeben — Tenant-Auflösung erfolgt im Dashboard-API-Route.
return [{ json: { ...payload, _resolved_did: didNumber } }];
